sp_widget.client_script:
api.controller = function() {
  var c = this;
  c.data = c.data || {};
  c.searchTerm = '';
  c.loading = false;

  c.search = function() {
    if (!c.searchTerm) {
      c.data.errorMsg = 'Please enter a case number or email.';
      return;
    }
    c.loading = true;
    c.data.errorMsg = '';
    c.server.get({ action: 'search', searchTerm: c.searchTerm }).then(function(r) {
      c.data = r.data;
      c.loading = false;
    }, function() {
      c.loading = false;
      c.data.errorMsg = 'Search failed. Please try again.';
    });
  };

  c.getStateClass = function(state) {
    if (!state) return 'label-default';
    var s = state.toLowerCase();
    if (s === 'open' || s === 'pending') return 'label-info';
    if (s === 'work in progress') return 'label-warning';
    if (s === 'closed complete') return 'label-success';
    if (s === 'closed incomplete' || s === 'closed skipped') return 'label-default';
    return 'label-default';
  };
};

sp_widget.css:
.sp-input {
  height: $input-height-base;
  border: 1px solid $border-tertiary;
  border-radius: $border-radius-base;
  font-size: $font-size-base;
  color: $text-color;
  background: $background-primary;
  &:focus {
    border-color: $brand-primary;
    box-shadow: 0 0 0 3px rgba($brand-primary, 0.15);
    outline: none;
  }
}
.sp-btn-primary {
  height: $input-height-base;
  padding: 0 20px;
  border-radius: $border-radius-base;
  font-size: $font-size-base;
  font-weight: 500;
  display: inline-flex;
  align-items: center;
  gap: 8px;
  border: none;
  background: $brand-primary;
  color: $btn-primary-color;
  &:hover:not(:disabled) {
    background: $brand-primary-dark;
    color: $btn-primary-color;
  }
}
.sp-table-wrapper {
  border: 1px solid $border-tertiary;
  border-radius: $border-radius-large;
  overflow: hidden;
  background: $background-primary;
  margin-top: 24px;
}
.sp-th {
  font-size: 12px;
  font-weight: 600;
  color: $text-muted;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  padding: 12px 16px;
  border-bottom: 2px solid $border-tertiary;
  background: $background-secondary;
}
.sp-td {
  font-size: $font-size-small;
  padding: 12px 16px;
  color: $text-color;
  border-bottom: 1px solid $border-tertiary;
  vertical-align: middle;
}
.sp-empty-state {
  padding: 64px 24px;
}
.sp-empty-icon {
  font-size: 48px;
  margin-bottom: 16px;
  display: block;
  opacity: 0.35;
  color: $text-muted;
}
.sp-empty-title {
  font-size: $font-size-large;
  font-weight: 600;
  color: $text-color;
  margin-bottom: 8px;
}
@keyframes sp-spin { to { transform: rotate(360deg); } }
.sp-spin { animation: sp-spin 0.8s linear infinite; }

sp_widget.script:
(function() {
  data.records = [];
  data.searched = false;
  data.errorMsg = '';

  try {
    if (input && input.action === 'search') {
      data.searched = true;
      var searchTerm = input.searchTerm || '';
      if (!searchTerm) {
        data.errorMsg = 'Please enter a case number or email to search.';
        return;
      }

      var gr = new GlideRecord('x_2091449_manage_0_consumer_case');
      var qc = gr.addQuery('number', 'CONTAINS', searchTerm);
      qc.addOrCondition('customer_email', searchTerm);
      gr.orderByDesc('sys_created_on');
      gr.setLimit(20);
      gr.query();
      while (gr.next()) {
        data.records.push({
          sys_id: gr.getUniqueValue(),
          number: gr.getValue('number') + '',
          short_description: gr.getValue('short_description') + '',
          state: gr.getDisplayValue('state') + '',
          priority: gr.getDisplayValue('priority') + '',
          assignment_group: gr.getDisplayValue('assignment_group') + '',
          opened_at: gr.getDisplayValue('opened_at') + ''
        });
      }
      return;
    }
  } catch (e) {
    gs.error('Track Complaint widget error: ' + e.message);
    data.errorMsg = 'An error occurred during search.';
  }
})();
